const CACHE_VERSION='flockos-v2.25';const API_CACHE='flockos-api-v1';const APP_SHELL=['./','./index.html','./manifest.json','./FlockOS-GS/Revelation/the_good_shepherd.min.html','./FlockOS-GS/Revelation/the_wall.min.html','./FlockOS-GS/Revelation/the_pentecost.min.html','./FlockOS-GS/Revelation/fishing-for-men.min.html','./FlockOS-GS/Revelation/the_generations.min.html','./FlockOS-GS/Revelation/the_weavers_plan.min.html','./FlockOS-GS/Revelation/the_gift_drift.min.html','./FlockOS-GS/Revelation/the_anatomy_of_worship.min.html','./FlockOS-GS/Revelation/the_call_to_forgive.min.html','./FlockOS-GS/Revelation/prayerful_action.min.html','./FlockOS-GS/Revelation/the_invitation.min.html','./FlockOS-GS/Revelation/FlockOS_White.png','./FlockOS-GS/Revelation/FlockOS_Blue.png','./FlockOS-GS/Acts/firm_foundation.min.js','./FlockOS-GS/Acts/fine_linen.min.js','./FlockOS-GS/Acts/the_cornerstone.min.js','./FlockOS-GS/Acts/the_true_vine.min.js','./FlockOS-GS/Acts/the_wellspring.min.js','./FlockOS-GS/Acts/the_well.min.js','./FlockOS-GS/Acts/the_tabernacle.min.js','./FlockOS-GS/Acts/the_seasons.min.js','./FlockOS-GS/Acts/the_way.min.js','./FlockOS-GS/Acts/the_harvest.min.js','./FlockOS-GS/Acts/the_life.min.js','./FlockOS-GS/Acts/the_scrolls.min.js','./FlockOS-GS/Acts/the_shepherd.min.js','./FlockOS-GS/Acts/love_in_action.min.js','./FlockOS-GS/Acts/the_fold.min.js','./FlockOS-GS/Acts/the_shofar.min.js','./FlockOS-GS/Acts/the_trumpet.min.js','./FlockOS-GS/Revelation/the_commission.min.js',];const API_HOSTS=['script.google.com','script.googleusercontent.com'];self.addEventListener('install',(event)=>{event.waitUntil(caches.open(CACHE_VERSION).then(cache=>cache.addAll(APP_SHELL)).then(()=>self.skipWaiting()));});self.addEventListener('activate',(event)=>{event.waitUntil(caches.keys().then(keys=>Promise.all(keys.filter(k=>k!==CACHE_VERSION&&k!==API_CACHE).map(k=>caches.delete(k)))).then(()=>self.clients.claim()));});self.addEventListener('fetch',(event)=>{const url=new URL(event.request.url);if(event.request.method!=='GET')return;if(API_HOSTS.some(h=>url.hostname.includes(h))){event.respondWith(networkFirstAPI(event.request));return;}
if(url.hostname.includes('fonts.googleapis.com')||url.hostname.includes('fonts.gstatic.com')){event.respondWith(cacheFirst(event.request));return;}
event.respondWith(cacheFirst(event.request));});async function cacheFirst(request){const cached=await caches.match(request);if(cached)return cached;try{const response=await fetch(request);if(response.ok){const cache=await caches.open(CACHE_VERSION);cache.put(request,response.clone());}
return response;}catch(_){return offlineFallback();}}
async function networkFirstAPI(request){try{const response=await fetch(request);if(response.ok){const cache=await caches.open(API_CACHE);cache.put(request,response.clone());}
return response;}catch(_){const cached=await caches.match(request);if(cached)return cached;return new Response(JSON.stringify({ok:false,error:'offline',message:'You are offline. Data will sync when you reconnect.'}),{status:503,headers:{'Content-Type':'application/json'}});}}
function offlineFallback(){const html=`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>FlockOS — Offline</title>
  <style>
    body {
      margin: 0; min-height: 100vh;
      display: flex; align-items: center; justify-content: center;
      background: linear-gradient(135deg, #1a1a2e, #0f2027, #1a1a2e);
      color: #ccc; font-family: 'Noto Sans', sans-serif; text-align: center;
    }
    .offline-card {
      background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1);
      border-radius: 16px; padding: 40px 32px; max-width: 380px;
    }
    h1 { font-size: 1.5rem; color: #e8a838; margin-bottom: 8px; }
    p { font-size: 0.95rem; line-height: 1.5; color: #999; }
    button {
      margin-top: 20px; padding: 10px 28px; border: none; border-radius: 8px;
      background: #e8a838; color: #1a1a2e; font-weight: 600; cursor: pointer;
    }
  </style>
</head>
<body>
  <div class="offline-card">
    <h1>You're Offline</h1>
    <p>FlockOS can't reach the server right now. Your data is safe and will sync automatically when you reconnect.</p>
    <button onclick="location.reload()">Try Again</button>
  </div>
</body>
</html>`;return new Response(html,{status:200,headers:{'Content-Type':'text/html'}});}
self.addEventListener('message',(event)=>{if(event.data==='skipWaiting'){self.skipWaiting();}
if(event.data==='clearCache'){caches.keys().then(keys=>keys.forEach(k=>caches.delete(k)));}});